SkillManager = {}

local skillList = {}

local RecyclingTime = 60

local SkillMap = {
    [Define.SkillType.Throw] = ThrowSkill,
    [Define.SkillType.Beat] = BeatSkill,
    [Define.SkillType.Toy] = ToySkill,
    [Define.SkillType.Common] = CommonSkill,
}

local function createSkill(userId, skillId)
    local config = SkillConfig:getSkillById(skillId)
    if config == nil then
        config = TokenSkillConfig:getSkillById(skillId)
    end

    if config == nil then
        return nil
    end

    local skillClass = SkillMap[config.skillType]
    if skillClass == nil then
        return nil
    end

    local skill = skillClass.new(userId, config)
    return skill
end

local function destroySkill(skill)
    skillList[skill.uuid] = nil
end

function SkillManager:init()
    --TODO
end

function SkillManager:getSkill(uuid)
    return skillList[uuid]
end

function SkillManager:playSkill(userId, skillId)
    local skill = createSkill(userId, skillId)
    if skill then
        skillList[skill.uuid] = skill
    end
end

function SkillManager:onTick(ticks)
    local count = 0
    for _, skill in pairs(skillList) do
        if skill.skillStage == Define.SkillStage.SkillEnd or os.time() - skill.createTime > RecyclingTime then
            destroySkill(skill)
        else
            skill:onTick(ticks)
        end
        count = count + 1
    end

    if count > 0 then
        --print(string.format("SkillManager:onTick count:%d", count))
    end
end

return SkillManager